window.marked={parse:function(input){function esc(s){return String(s??"").replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#039;")}function inline(s){return esc(s).replace(/&lt;br\s*\/?&gt;/gi,"<br>").replace(/\*\*([^*]+)\*\*/g,"<strong>$1</strong>").replace(/`([^`]+)`/g,"<code>$1</code>")}function cells(line){return line.trim().replace(/^\|/,"").replace(/\|$/,"").split("|").map(x=>x.trim())}function isSep(line){const parts=cells(line);return parts.length>1&&parts.every(x=>/^:?-{3,}:?$/.test(x))}const lines=String(input??"").replace(/\r\n/g,"\n").split("\n");let html=[],para=[],list=[],listType="ul",listStart=null;function flushPara(){if(para.length){html.push("<p>"+inline(para.join(" "))+"</p>");para=[]}}function flushList(){if(list.length){const start=listType==="ol"&&listStart&&listStart!==1?' start="'+listStart+'"':"";html.push("<"+listType+start+">"+list.map(x=>"<li>"+inline(x)+"</li>").join("")+"</"+listType+">");list=[];listType="ul";listStart=null}}function addList(type,item,start){if(list.length&&listType!==type)flushList();listType=type;if(type==="ol"&&!list.length)listStart=start||1;list.push(item)}for(let idx=0;idx<lines.length;idx++){const line=lines[idx].trim();if(!line){flushPara();flushList();continue}if(/^(-{3,}|\*{3,}|_{3,})$/.test(line)){flushPara();flushList();html.push("<hr>");continue}if(line.includes("|")&&idx+1<lines.length&&isSep(lines[idx+1].trim())){flushPara();flushList();const headers=cells(line);idx+=2;let rows=[];while(idx<lines.length&&lines[idx].trim().includes("|")&&lines[idx].trim()){rows.push(cells(lines[idx].trim()));idx++}idx--;html.push("<table><thead><tr>"+headers.map(h=>"<th>"+inline(h)+"</th>").join("")+"</tr></thead><tbody>"+rows.map(r=>"<tr>"+headers.map((_,i)=>"<td>"+inline(r[i]??"")+"</td>").join("")+"</tr>").join("")+"</tbody></table>");continue}const h=line.match(/^(#{1,6})\s+(.+)$/);if(h){flushPara();flushList();const level=Math.min(h[1].length,6);html.push("<h"+level+">"+inline(h[2])+"</h"+level+">");continue}const ordered=line.match(/^(\d+)\.\s+(.+)$/);if(ordered){flushPara();addList("ol",ordered[2],Number(ordered[1]));continue}const bullet=line.match(/^[-*]\s+(.+)$/);if(bullet){flushPara();addList("ul",bullet[1]);continue}flushList();para.push(line)}flushPara();flushList();return html.join("")}};
